type recoveryFakeRunner struct{ paneID string }

func (r recoveryFakeRunner) Start(
	ctx context.Context,
	req ChildRunRequest,
) (ChildRun, error) {
	return ChildRun{
		ID:         req.ID,
		Pane:       TmuxPane{ID: r.paneID},
		OutputPath: req.OutputPath,
		SessionID:  req.SessionID,
		SessionDir: req.SessionDir,
		DonePath:   req.DonePath,
		StatusPath: req.StatusPath,
	}, nil
}

func (r recoveryFakeRunner) Wait(
	ctx context.Context,
	run ChildRun,
) (ChildRunResult, error) {
	return ChildRunResult{
		ID:         run.ID,
		OutputPath: run.OutputPath,
		SessionID:  run.SessionID,
		SessionDir: run.SessionDir,
		DonePath:   run.DonePath,
		StatusPath: run.StatusPath,
	}, nil
}

func chtimes(t *testing.T, path string, ts time.Time) {
	t.Helper()
	if err := os.Chtimes(path, ts, ts); err != nil {
		t.Fatal(err)
	}
}

