	if err := os.MkdirAll(
		filepath.Join(projectRoot, "thoughts", "example"),
		0o755,
	); err != nil {
		t.Fatal(err)
	}
	return managerFlowFixture{
		dir:         dir,
		projectRoot: projectRoot,
		stateRoot:   filepath.Join(dir, "state"),
		planDir:     "thoughts/example",
	}
}

func (f managerFlowFixture) clock() time.Time               { return time.Unix(100, 123) }
func (f managerFlowFixture) stateRootFunc() (string, error) { return f.stateRoot, nil }

func (f managerFlowFixture) init(t *testing.T) string {
	t.Helper()
	var out bytes.Buffer
	if err := RunInit(
		t.Context(),
		InitOptions{PlanDir: f.planDir, ProjectRoot: f.projectRoot},
		deps{StateRoot: f.stateRootFunc, Clock: f.clock},
		&out,
	); err != nil {
		t.Fatalf("RunInit error = %v", err)
	}
	return eventRefString(t, out.String(), "stateFile")
}

func executeManagerCommand(d deps, args ...string) (string, error) {
	out, _, err := executeManagerCommandWithErr(d, args...)
	return out, err
}

func executeManagerCommandWithErr(d deps, args ...string) (string, string, error) {
	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd := newCommand(d)
	cmd.SetOut(&out)
	cmd.SetErr(&stderr)
	cmd.SetArgs(args)
	err := cmd.Execute()
	return out.String(), stderr.String(), err
}

func eventRefString(t *testing.T, ndjson, key string) string {
	t.Helper()
	dec := json.NewDecoder(strings.NewReader(ndjson))
	for dec.More() {
		var event Event
		if err := dec.Decode(&event); err != nil {
			t.Fatalf("decode event from %q: %v", ndjson, err)
		}
		if value, ok := event.Ref[key].(string); ok {
			return value
		}
	}
	t.Fatalf("missing ref %q in %q", key, ndjson)
	return ""
}

func loadManagerState(t *testing.T, path string) ManagerState {
	t.Helper()
	state, err := (FileStateStore{}).Load(path)
	if err != nil {
		t.Fatal(err)
	}
	return state
}

func saveManagerState(t *testing.T, path string, state ManagerState) {
	t.Helper()
	if err := (FileStateStore{}).Save(path, state); err != nil {
		t.Fatal(err)
	}
}

func readLock(t *testing.T, path string) Lock {
	t.Helper()
	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatal(err)
	}
	var lock Lock
	if err := json.Unmarshal(data, &lock); err != nil {
		t.Fatal(err)
	}
	return lock
}

func writeFile(t *testing.T, path, content string) {
	t.Helper()
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

package qrspicmd

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/CoreyCole/vamos/pkg/agents/workflows/qrspi"
	"github.com/CoreyCole/vamos/pkg/agents/workflows/qrspi/semantic"
	wruntime "github.com/CoreyCole/vamos/pkg/agents/workflows/runtime"
)

type ParsedDecision struct {
	Result         wruntime.WorkflowResult     `json:"result"`
	Decision       wruntime.TransitionDecision `json:"decision"`
	RawYAML        string                      `json:"rawYaml,omitempty"`
	Normalizations []ResultNormalization       `json:"normalizations,omitempty"`
}

type InitOverrides struct {
	NodeID            string
	ImplementationCwd string
	PiModel           string
}

func Definition() (wruntime.Definition, error) {
	return qrspi.Definition()
}

func InitialManagerState(
	planDir, projectRoot string,
	policy json.RawMessage,
) (ManagerState, error) {
	def, err := Definition()
	if err != nil {
		return ManagerState{}, err
	}
	workflow, err := wruntime.InitialState(def, policy)
	if err != nil {
		return ManagerState{}, err
	}
	canonicalPlanDir, err := CanonicalPlanDir(projectRoot, planDir)
	if err != nil {
		return ManagerState{}, err
	}
	repoID, err := RepoID(projectRoot)
	if err != nil {
		return ManagerState{}, err
	}
	workflow.ExecutionCwd = projectRoot
	return ManagerState{
		SchemaVersion:    schemaVersion,
		RepoID:           repoID,
		CanonicalPlanDir: canonicalPlanDir,
		SourceCwd:        projectRoot,
		Workflow:         workflow,
	}, nil
}

func ApplyInitOverrides(state *ManagerState, opts InitOverrides) error {
	if state == nil {
		return nil
	}
	if nodeID := wruntime.NodeID(strings.TrimSpace(opts.NodeID)); nodeID != "" {
		def, err := Definition()
		if err != nil {
			return err
		}
		if _, ok := def.Nodes[nodeID]; !ok {
			return fmt.Errorf("node %q is not in QRSPI definition", nodeID)
		}
		state.Workflow.CurrentNodeID = nodeID
	}
	if implementationCwd := strings.TrimSpace(
		opts.ImplementationCwd,
	); implementationCwd != "" {
		state.ImplementationCwd = implementationCwd
	}
	if piModel := strings.TrimSpace(opts.PiModel); piModel != "" {
		state.PiModel = piModel
	}
	return nil
}

func ParseValidateDecide(
	output string,
	state wruntime.State,
	ctx wruntime.ParseContext,
) (ParsedDecision, error) {
	return parseValidateDecide(output, ManagerState{Workflow: state}, ctx, false)
}

func ParseNormalizeValidateDecide(
	output string,
	manager ManagerState,
	ctx wruntime.ParseContext,
) (ParsedDecision, error) {
	return parseValidateDecide(output, manager, ctx, true)
}

func parseValidateDecide(
	output string,
	manager ManagerState,
	ctx wruntime.ParseContext,
	managerAware bool,
) (ParsedDecision, error) {
	def, err := Definition()
	if err != nil {
		return ParsedDecision{}, err
	}
	ctx.WorkflowType = string(qrspi.AgentChatWorkflowType)
	if ctx.ExpectedNodeID == "" {
		ctx.ExpectedNodeID = manager.Workflow.CurrentNodeID
	}
	semCtx := semantic.Context{
		WorkflowType:      qrspi.AgentChatWorkflowType,
		State:             manager.Workflow,
		ExpectedNodeID:    ctx.ExpectedNodeID,
		Source:            semantic.SourceCLIChildSession,
		PlanDir:           manager.CanonicalPlanDir,
		ImplementationCwd: manager.ImplementationCwd,
		PlanningCwd:       manager.SourceCwd,
		RunID:             ctx.RunID,
	}
	if !managerAware {
		semCtx.PlanDir = ""
		semCtx.ImplementationCwd = ""
	}
	applied, err := semantic.Apply(nil, semantic.ApplyInput{
		Definition:   def,
		RawOutput:    output,
		ParseContext: ctx,
		Context:      semCtx,
	})
	if err != nil {
		return ParsedDecision{}, GraphContractError(err)
	}
	rawYAML, _ := qrspi.ExtractQRSPIResultYAML(output)
	return ParsedDecision{
		Result:         applied.WorkflowResult,
		Decision:       applied.Decision,
		RawYAML:        rawYAML,
		Normalizations: resultNormalizations(applied.Normalizations),
	}, nil
}

func resultNormalizations(in []semantic.Normalization) []ResultNormalization {
	out := make([]ResultNormalization, 0, len(in))
	for _, n := range in {
		out = append(
			out,
			ResultNormalization{
				Field:     n.Field,
				Original:  n.Original,
				Canonical: n.Canonical,
				Reason:    n.Reason,
			},
		)
	}
	return out
}

func UpdateImplementationCwd(
	state ManagerState,
	result wruntime.WorkflowResult,
) ManagerState {
	implementation := strings.TrimSpace(
		qrspi.WorkflowResultImplementationWorkspace(result),
	)
	if implementation != "" {
		state.ImplementationCwd = implementation
	}
	return state
}

func CorrectionPrompt(err error, attempt int) string {
	return qrspi.QRSPIResultParser{}.CorrectionPrompt(err, attempt)
}

func ChildRecoveryPrompt(err error, attempt int) string {
	if IsChildProviderError(err) || isChildProviderErrorText(err) {
		return providerErrorRecoveryPrompt(err, attempt)
	}
	return CorrectionPrompt(err, attempt)
}

func isChildProviderErrorText(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(err.Error(), "ended with provider error before qrspi_result")
}

func providerErrorRecoveryPrompt(err error, attempt int) string {
	return fmt.Sprintf(
		`Your previous turn ended with a provider/runtime error, not a QRSPI stage result.

Recovery reason: %s
Attempt: %d

Continue the same QRSPI stage from the last durable context and current workspace state. Do not emit a synthetic qrspi_result just to satisfy validation. Do not treat any previous YAML correction prompt as task guidance.

When real stage work reaches a handoff, completion, blocker, or error, emit the required fenced yaml block with top-level qrspi_result. If work is still in progress, continue implementing now.
`,
		err.Error(),
		attempt,
	)
}

func GraphContractError(err error) error {
	if err == nil {
		return nil
	}
	return fmt.Errorf("canonical QRSPI graph rejected result: %w", err)
}

package qrspicmd

import (
	"bufio"
	"bytes"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type sessionEntry struct {
	Type      string          `json:"type"`
	ID        string          `json:"id,omitempty"`
	Cwd       string          `json:"cwd,omitempty"`
	Timestamp string          `json:"timestamp,omitempty"`
	Message   *sessionMessage `json:"message,omitempty"`
}

type sessionMessage struct {
	Role         string          `json:"role"`
	Content      json.RawMessage `json:"content"`
	StopReason   string          `json:"stopReason,omitempty"`
	ErrorMessage string          `json:"errorMessage,omitempty"`
}

type AssistantTerminalEvidence struct {
	SessionPath        string `json:"sessionPath,omitempty"`
	SessionID          string `json:"sessionId,omitempty"`
	Line               int    `json:"line,omitempty"`
	Timestamp          string `json:"timestamp,omitempty"`
	StopReason         string `json:"stopReason,omitempty"`
	ErrorMessage       string `json:"errorMessage,omitempty"`
	ContextWindowError bool   `json:"contextWindowError,omitempty"`
	EvidenceID         string `json:"evidenceId,omitempty"`
}

type sessionContentBlock struct {
	Type string `json:"type"`
	Text string `json:"text,omitempty"`
}

func ResolveSessionPath(sessionDir, sessionID, cwd string) (string, error) {
	if strings.TrimSpace(sessionDir) == "" || strings.TrimSpace(sessionID) == "" {
		return "", errors.New("session dir and session id are required")
	}

	if _, err := os.Stat(sessionDir); err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
		}
		return "", err
	}

	var matches []string
	walkErr := filepath.WalkDir(
		sessionDir,
		func(path string, entry os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if entry.IsDir() || filepath.Ext(entry.Name()) != ".jsonl" {
				return nil
			}
			header, err := readSessionHeader(path)
			if err != nil {
				return nil
			}
			if header.Type == "session" && header.ID == sessionID &&
				(strings.TrimSpace(cwd) == "" || header.Cwd == cwd) {
				matches = append(matches, path)
			}
			return nil
		},
	)
	if walkErr != nil {
		return "", walkErr
	}

	switch len(matches) {
	case 1:
		return matches[0], nil
	case 0:
		return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
	default:
		return "", fmt.Errorf(
			"session %q matched multiple files in %s",
			sessionID,
			sessionDir,
		)
	}
}

func readSessionHeader(path string) (sessionEntry, error) {
	file, err := os.Open(path)
	if err != nil {
		return sessionEntry{}, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	if !scanner.Scan() {
		if err := scanner.Err(); err != nil {
			return sessionEntry{}, err
		}
		return sessionEntry{}, errors.New("empty session file")
	}
	var header sessionEntry
	if err := json.Unmarshal(bytes.TrimSpace(scanner.Bytes()), &header); err != nil {
		return sessionEntry{}, err
	}
	return header, nil
}

type ChildProviderError struct {
	SessionPath string
}

func (e ChildProviderError) Error() string {
	return fmt.Sprintf(
		"session %s ended with provider error before qrspi_result",
		e.SessionPath,
	)
}

func IsChildProviderError(err error) bool {
	var providerErr ChildProviderError
	return errors.As(err, &providerErr)
}

func LatestAssistantTerminalEvidence(
	path string,
) (AssistantTerminalEvidence, bool, error) {
	file, err := os.Open(path)
	if err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	defer file.Close()

	sessionID := ""
	var latest AssistantTerminalEvidence
	found := false
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	lineNo := 0
	for scanner.Scan() {
		lineNo++
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type == "session" && strings.TrimSpace(entry.ID) != "" {
			sessionID = entry.ID
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if strings.TrimSpace(entry.Message.StopReason) == "" &&
			strings.TrimSpace(entry.Message.ErrorMessage) == "" {
			continue
		}
		evidence := AssistantTerminalEvidence{
			SessionPath:  path,
			SessionID:    sessionID,
			Line:         lineNo,
			Timestamp:    entry.Timestamp,
			StopReason:   entry.Message.StopReason,
			ErrorMessage: entry.Message.ErrorMessage,
		}
		evidence.ContextWindowError = strings.EqualFold(evidence.StopReason, "error") &&
			IsContextWindowErrorMessage(evidence.ErrorMessage)
		evidence.EvidenceID = terminalEvidenceID(evidence)
		latest = evidence
		found = true
	}
	if err := scanner.Err(); err != nil {
		return AssistantTerminalEvidence{}, false, err
	}
	return latest, found, nil
}

func IsContextWindowErrorMessage(message string) bool {
	text := strings.ToLower(message)
	needles := []string{
		"context window",
		"context length",
		"context_length_exceeded",
		"maximum context",
		"context limit",
		"input exceeds",
	}
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}

func terminalEvidenceID(e AssistantTerminalEvidence) string {
	raw := strings.Join([]string{
		strings.TrimSpace(e.SessionID),
		filepath.Clean(strings.TrimSpace(e.SessionPath)),
		fmt.Sprintf("%d", e.Line),
		strings.TrimSpace(e.Timestamp),
		strings.TrimSpace(e.StopReason),
		strings.TrimSpace(e.ErrorMessage),
	}, "\x00")
	sum := sha256.Sum256([]byte(raw))
	return hex.EncodeToString(sum[:])[:16]
}

func ExtractFinalAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, true)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf(
			"session %s has no assistant text containing qrspi_result",
			path,
		)
	}
	return last, nil
}

func ExtractLastAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, false)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf("session %s has no assistant text", path)
	}
	return last, nil
}

func extractLastAssistantTextFromSession(
	path string,
	requireQRSPIResult bool,
) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	var last string
	scanner := bufio.NewScanner(file)

[53 more lines in file. Use offset=261 to continue.]

	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if requireQRSPIResult && entry.Message.StopReason == "error" {
			continue
		}
		if requireQRSPIResult && entry.Message.StopReason == "aborted" {
			continue
		}
		text := textBlocksFromAssistantMessage(*entry.Message)
		if strings.TrimSpace(text) == "" {
			continue
		}
		if !requireQRSPIResult || strings.Contains(text, "qrspi_result") {
			last = text
		}
	}
	if err := scanner.Err(); err != nil {
		return "", err
	}
	return last, nil
}

func textBlocksFromAssistantMessage(msg sessionMessage) string {
	var blocks []sessionContentBlock
	if err := json.Unmarshal(msg.Content, &blocks); err == nil {
		var parts []string
		for _, block := range blocks {
			if block.Type == "text" && block.Text != "" {
				parts = append(parts, block.Text)
			}
		}
		return strings.Join(parts, "\n")
	}

	var text string
	if err := json.Unmarshal(msg.Content, &text); err == nil {
		return text
	}
	return ""
}

