const MAX_COMMAND_OUTPUT_BYTES = 1024 * 1024;

let lastRotationError = "";

async function runVamosJson(args) {
  return new Promise((resolve) => {
    const child = spawn("vamos", args, { stdio: ["ignore", "pipe", "pipe"] });
    let stdout = "";
    let stderr = "";
    let overflow = false;
    const collect = (current, chunk) => {
      const next = current + chunk.toString();
      if (Buffer.byteLength(next) > MAX_COMMAND_OUTPUT_BYTES) {
        overflow = true;
        child.kill();
        return current;
      }
      return next;
    };
    child.stdout.on("data", (chunk) => {
      stdout = collect(stdout, chunk);
    });
    child.stderr.on("data", (chunk) => {
      stderr = collect(stderr, chunk);
    });
    child.on("close", (code) => {
      if (overflow) {
        resolve({ value: null, error: "vamos command output exceeded 1 MiB" });
        return;
      }
      if (code !== 0) {
        resolve({ value: null, error: stderr.trim() || `vamos exited ${code}` });
        return;
      }
      try {
        resolve({ value: JSON.parse(stdout), error: "" });
      } catch {
        resolve({ value: null, error: "vamos returned malformed JSON" });
      }
    });
    child.on("error", (error) => resolve({ value: null, error: error.message }));
  });
}

async function runChildComplete() {
  const stateFile = process.env.Q_MANAGER_STATE_FILE || "";
  const childID = process.env.Q_MANAGER_CHILD_ID || "";
  if (!stateFile || !childID) return null;
  const result = await runVamosJson([
    "qrspi",
    "child-complete",
    "--state-file",
    stateFile,
    "--child-id",
    childID,
    "--output",
    "json",
  ]);
  return result.value;
}

async function requestRotation({ stateFile, childId, sessionPath, usagePercent }) {
  if (!stateFile || !childId || !sessionPath) return null;
  const result = await runVamosJson([
    "qrspi",
    "rotation-request",
    "--state-file",
    stateFile,
    "--role",
    "child",
    "--child-id",
    childId,
    "--session-path",
    sessionPath,
    "--usage-percent",
    String(usagePercent),
    "--usage-source",
    "pi-turn-end",
    "--output",
    "json",
  ]);
  lastRotationError = result.error;
  return result.value;
}

pi.on("turn_end", async (_event, ctx) => {
  const usage = ctx.getContextUsage();
  if (!usage || usage.percent === null || !Number.isFinite(usage.percent)) return;
  const result = await requestRotation({
    stateFile: process.env.Q_MANAGER_STATE_FILE || "",
    childId: process.env.Q_MANAGER_CHILD_ID || "",
    sessionPath: ctx.sessionManager.getSessionFile() || "",
    usagePercent: usage.percent,
  });
  if (result?.requested === true && result.prompt) {
    pi.sendUserMessage(result.prompt, { deliverAs: "steer" });
  }
});

pi.on("session_before_compact", () => ({ cancel: true }));

pi.on("agent_end", async () => {

  wakeDeliveryReason: validation?.wake?.reason || "",
  rotationRequestError: lastRotationError,
};

