package qrspicmd

import (
	"encoding/json"
	"math"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/CoreyCole/vamos/pkg/agents/workflows/qrspi"
)

func TestNormalizedRotationThreshold(t *testing.T) {
	for _, tt := range []struct {
		name    string
		input   float64
		want    float64
		wantErr bool
	}{
		{name: "default", input: 0, want: 75},
		{name: "override", input: 82.5, want: 82.5},
		{name: "negative", input: -1, wantErr: true},
		{name: "hundred", input: 100, wantErr: true},
		{name: "nan", input: math.NaN(), wantErr: true},
	} {
		t.Run(tt.name, func(t *testing.T) {
			got, err := normalizedRotationThreshold(tt.input)
			if tt.wantErr {
				if err == nil {
					t.Fatalf("normalizedRotationThreshold(%v) = %v, want error", tt.input, got)
				}
				return
			}
			if err != nil || got != tt.want {
				t.Fatalf("normalizedRotationThreshold(%v) = %v, %v; want %v", tt.input, got, err, tt.want)
			}
		})
	}
}

func TestRequestSessionRotationUsageThresholds(t *testing.T) {
	now := time.Date(2026, 7, 16, 20, 0, 0, 123, time.UTC)
	for _, tt := range []struct {
		name      string
		usage     ManagerUsageInput
		threshold float64
		want      bool
		wantReason string
	}{
		{name: "unknown", wantReason: "unknown_usage"},
		{name: "below", usage: usagePercentInput(74.9), wantReason: "below_threshold"},
		{name: "equal", usage: usagePercentInput(75), want: true, wantReason: "threshold_met"},
		{name: "token fallback", usage: usageTokenInput(750, 1000), want: true, wantReason: "threshold_met"},
		{name: "explicit threshold below", usage: usagePercentInput(79), threshold: 80, wantReason: "below_threshold"},
		{name: "explicit threshold equal", usage: usagePercentInput(80), threshold: 80, want: true, wantReason: "threshold_met"},
	} {
		t.Run(tt.name, func(t *testing.T) {
			state, opts := rotationChildFixture(t)
			state.Rotations.Config.ThresholdPercent = tt.threshold
			opts.Usage = tt.usage
			next, status, err := requestSessionRotation(state, opts, now)
			if err != nil {
				t.Fatalf("requestSessionRotation error = %v", err)
			}
			if status.Requested != tt.want || status.Reason != tt.wantReason {
				t.Fatalf("status = %+v", status)
			}
			wantThreshold := tt.threshold
			if wantThreshold == 0 {
				wantThreshold = defaultRotationThresholdPercent
			}
			if next.Rotations.Config.ThresholdPercent != wantThreshold {
				t.Fatalf("threshold = %v, want %v", next.Rotations.Config.ThresholdPercent, wantThreshold)
			}
			if tt.usage.UsagePercent != nil || tt.usage.Tokens != nil {
				if next.LastManagerUsage == nil {
					t.Fatal("usage sample not persisted")
				}
			}
			if tt.want {
				if next.Rotations.Child == nil || next.Rotations.Child.Usage.Percent == nil ||
					*next.Rotations.Child.Usage.Percent < wantThreshold {
					t.Fatalf("rotation = %+v", next.Rotations.Child)
				}
			}
		})
	}
}

func TestRequestSessionRotationChildIdentityAndDuplicateGuard(t *testing.T) {
	state, opts := rotationChildFixture(t)
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	opts.Usage = usagePercentInput(75)
	state.ActiveChild.SessionPath = ""

	requested, first, err := requestSessionRotation(state, opts, now)
	if err != nil {
		t.Fatalf("first request error = %v", err)
	}
	if !first.Requested || requested.ActiveChild.SessionPath != opts.SessionPath ||
		requested.Rotations.Child == nil || requested.Rotations.Child.SourceGeneration != 3 {
		t.Fatalf("first status/state = %+v / %+v", first, requested)
	}
	for _, want := range []string{first.RotationID, string(qrspi.NodeResearch), ".pi/skills/q-handoff/SKILL.md", "status: handoff", "no outcome"} {
		if !strings.Contains(first.Prompt, want) {
			t.Fatalf("prompt missing %q: %s", want, first.Prompt)
		}
	}

	duplicate, second, err := requestSessionRotation(requested, opts, now.Add(time.Second))
	if err != nil {
		t.Fatalf("duplicate request error = %v", err)
	}
	if second.Requested || second.Reason != "rotation_pending" ||
		second.RotationID != first.RotationID || duplicate.Rotations.Child.ID != first.RotationID {
		t.Fatalf("duplicate status/state = %+v / %+v", second, duplicate.Rotations.Child)
	}

	staleID := opts
	staleID.ChildID = "older-child"
	if _, _, err := requestSessionRotation(requested, staleID, now.Add(2*time.Second)); err == nil {
		t.Fatal("stale child ID accepted")
	}
	stalePath := writePiSession(
		t,
		requested.ActiveChild.SessionDir,
		"stale.jsonl",
		"stale-session",
		requested.ActiveChild.Cwd,
		assistantLine("stale"),
	)
	staleSession := opts
	staleSession.SessionPath = stalePath
	if _, _, err := requestSessionRotation(requested, staleSession, now.Add(3*time.Second)); err == nil {
		t.Fatal("stale child session accepted")
	}
	if requested.Rotations.Child.ID != first.RotationID || requested.Rotations.Child.Phase != RotationRequested {
		t.Fatalf("stale request mutated pending rotation: %+v", requested.Rotations.Child)
	}
}

func TestRequestSessionRotationManagerBindsExactSource(t *testing.T) {
	dir := t.TempDir()
	source := writePiSession(t, dir, "manager.jsonl", "manager-session", dir, assistantLine("manager"))
	other := writePiSession(t, dir, "other.jsonl", "other-session", dir, assistantLine("other"))
	state := ManagerState{
		Workflow: testWorkflowState(t, qrspi.NodeResearch, nil),
		Rotations: RotationState{Config: RotationConfig{ThresholdPercent: 75}},
	}
	opts := RotationRequestOptions{
		StateFile:   filepath.Join(dir, "state.json"),
		Role:        RotationRoleManager,
		SessionPath: source,
		Usage:       usagePercentInput(75),
	}
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	next, status, err := requestSessionRotation(state, opts, now)
	if err != nil {
		t.Fatalf("manager request error = %v", err)
	}
	if !status.Requested || next.ManagerSessionPath != source || next.Rotations.Manager == nil {
		t.Fatalf("status/state = %+v / %+v", status, next)
	}
	for _, want := range []string{status.RotationID, string(qrspi.NodeResearch), ".pi/skills/q-manager-handoff/SKILL.md", "Do not run /new"} {
		if !strings.Contains(status.Prompt, want) {
			t.Fatalf("manager prompt missing %q: %s", want, status.Prompt)
		}
	}
	stale := opts
	stale.SessionPath = other
	mutated, _, err := requestSessionRotation(next, stale, now.Add(time.Second))
	if err == nil {
		t.Fatal("stale manager session accepted")
	}
	if mutated.ManagerSessionPath != source || mutated.Rotations.Manager.ID != status.RotationID {
		t.Fatalf("stale request mutated manager state: %+v", mutated)
	}
}

func TestCompleteChildRotationRequiresMatchingContinuationLineage(t *testing.T) {
	state, opts := rotationChildFixture(t)
	opts.Usage = usagePercentInput(75)
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	requested, status, err := requestSessionRotation(state, opts, now)
	if err != nil || !status.Requested {
		t.Fatalf("request status=%+v err=%v", status, err)
	}
	source := *requested.ActiveChild
	continuation := ChildRunRef{
		ID:                     "successor",
		Stage:                  source.Stage,
		SessionPath:            filepath.Join(source.SessionDir, "successor.jsonl"),
		LaunchKind:             ChildLaunchResumeHandoff,
		ContinuationOf:         source.ID,
		ContinuationArtifact:   "thoughts/example/handoffs/research.md",
		ContinuationDeliveryID: "delivery-1",
	}
	requested.Workflow.LastResult = &requested.Workflow.LastResult
	_ = requested
	_ = continuation
}

func TestCompleteChildRotationTransitionsOnlyMatchingRequest(t *testing.T) {
	state, opts := rotationChildFixture(t)
	opts.Usage = usagePercentInput(75)
	now := time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC)
	requested, _, err := requestSessionRotation(state, opts, now)
	if err != nil {
		t.Fatal(err)
	}
	source := *requested.ActiveChild
	continuation := ChildRunRef{
		ID:                     "successor",
		Stage:                  source.Stage,
		LaunchKind:             ChildLaunchResumeHandoff,
		ContinuationOf:         source.ID,
		ContinuationArtifact:   "thoughts/example/handoffs/research.md",
		ContinuationDeliveryID: "delivery-1",
	}
	completed := completeChildRotation(requested, source, continuation, now.Add(time.Second))
	if completed.Rotations.Child.Phase != RotationSuccessorReady ||
		completed.Rotations.Child.SuccessorChildID != continuation.ID ||
		completed.Rotations.Child.HandoffArtifact != continuation.ContinuationArtifact {
		t.Fatalf("completed rotation = %+v", completed.Rotations.Child)
	}

	mismatched := requested
	badSource := source
	badSource.Generation++
	mismatched = completeChildRotation(mismatched, badSource, continuation, now.Add(time.Second))
	if mismatched.Rotations.Child.Phase != RotationRequested {
		t.Fatalf("mismatched rotation advanced: %+v", mismatched.Rotations.Child)
	}

	generic := requested
	generic.Rotations.Child = nil
	generic = completeChildRotation(generic, source, continuation, now.Add(time.Second))
	if generic.Rotations.Child != nil {
		t.Fatalf("generic handoff created rotation: %+v", generic.Rotations.Child)
	}
}

func TestRunRotationRequestPersistsBeforeJSONOutput(t *testing.T) {
	state, opts := rotationChildFixture(t)
	stateFile := filepath.Join(t.TempDir(), "state.json")
	opts.StateFile = stateFile
	opts.Output = "json"
	opts.Usage = usagePercentInput(75)
	saveManagerState(t, stateFile, state)
	var out strings.Builder
	if err := RunRotationRequest(
		t.Context(),
		opts,
		deps{Clock: func() time.Time { return time.Date(2026, 7, 16, 20, 0, 0, 0, time.UTC) }},
		&out,
	); err != nil {
		t.Fatalf("RunRotationRequest error = %v", err)
	}
	var status RotationRequestStatus
	if err := json.Unmarshal([]byte(out.String()), &status); err != nil {
		t.Fatalf("decode output %q: %v", out.String(), err)
	}
	loaded := loadManagerState(t, stateFile)
	if !status.Requested || loaded.Rotations.Child == nil ||
		loaded.Rotations.Child.ID != status.RotationID {
		t.Fatalf("status/state = %+v / %+v", status, loaded.Rotations.Child)
	}
}

