		return defaultRotationThresholdPercent, nil
	}
	if math.IsNaN(value) || math.IsInf(value, 0) || value <= 0 || value >= 100 {
		return 0, errors.New(
			"rotation-threshold-percent must be greater than 0 and less than 100",
		)
	}
	return value, nil
}

func rotationUsageFromChangedFlags(
	cmd *cobra.Command,
	usagePercent float64,
	usageTokens, usageWindow int,
	usageSource string,
) (ManagerUsageInput, error) {
	var input ManagerUsageInput
	percentSet := cmd.Flags().Changed("usage-percent")
	tokensSet := cmd.Flags().Changed("usage-tokens")
	windowSet := cmd.Flags().Changed("usage-window")
	if percentSet && (tokensSet || windowSet) {
		return input, errors.New(
			"use either --usage-percent or --usage-tokens with --usage-window",
		)
	}
	if tokensSet != windowSet {
		return input, errors.New(
			"usage-tokens and usage-window must be provided together",
		)
	}
	if percentSet {
		input.UsagePercent = &usagePercent
	}
	if tokensSet {
		input.Tokens = &usageTokens
		input.Window = &usageWindow
	}
	input.Source = strings.TrimSpace(usageSource)
	return input, validateRotationUsage(input)
}

func validateRotationUsage(input ManagerUsageInput) error {
	if input.UsagePercent != nil {
		value := *input.UsagePercent
		if math.IsNaN(value) || math.IsInf(value, 0) || value < 0 {
			return errors.New("usage-percent must be a finite non-negative number")
		}
	}
	if (input.Tokens == nil) != (input.Window == nil) {
		return errors.New("usage tokens and window must be provided together")
	}
	if input.Tokens != nil && *input.Tokens < 0 {
		return errors.New("usage-tokens must be non-negative")
	}
	if input.Window != nil && *input.Window <= 0 {
		return errors.New("usage-window must be greater than zero")
	}
	return nil
}

func validateRotationRequestOptions(opts RotationRequestOptions) error {
	if strings.TrimSpace(opts.StateFile) == "" {
		return errors.New("state-file is required")
	}
	if opts.Role != RotationRoleManager && opts.Role != RotationRoleChild {
		return fmt.Errorf("invalid rotation role %q", opts.Role)
	}
	if strings.TrimSpace(opts.SessionPath) == "" {
		return errors.New("session-path is required")
	}
	if opts.Role == RotationRoleChild && strings.TrimSpace(opts.ChildID) == "" {
		return errors.New("child-id is required for child rotation")
	}
	if opts.Role == RotationRoleManager && strings.TrimSpace(opts.ChildID) != "" {
		return errors.New("child-id is only valid for child rotation")
	}
	if err := validateRotationUsage(opts.Usage); err != nil {
		return err
	}
	switch strings.ToLower(strings.TrimSpace(opts.Output)) {
	case "", "text", "json":
		return nil
	default:
		return fmt.Errorf("unsupported output format %q", opts.Output)
	}
}

func RunRotationRequest(
	ctx context.Context,
	opts RotationRequestOptions,
	d deps,
	out io.Writer,
) error {
	if err := validateRotationRequestOptions(opts); err != nil {
		return err
	}
	out = ensureWriter(out)
	store := stateStore(d, "", clockOrNow(d))
	lock, err := store.AcquireOperationLock(ctx, opts.StateFile)
	if err != nil {
		return err
	}
	defer lock.Release()

	state, err := store.Load(opts.StateFile)
	if err != nil {
		return err
	}
	next, status, err := requestSessionRotation(state, opts, clockOrNow(d)())
	if err != nil {
		return err
	}
	if err := store.Save(opts.StateFile, next); err != nil {
		return err
	}
	return writeRotationRequestOutput(out, opts.Output, status)
}

func requestSessionRotation(
	state ManagerState,
	opts RotationRequestOptions,
	now time.Time,
) (ManagerState, RotationRequestStatus, error) {
	original := state
	status := RotationRequestStatus{StateFile: opts.StateFile}
	threshold, err := normalizedRotationThreshold(state.Rotations.Config.ThresholdPercent)
	if err != nil {
		return original, status, err
	}
	state.Rotations.Config.ThresholdPercent = threshold

	sessionPath, err := canonicalSessionPath(opts.SessionPath)
	if err != nil {
		return original, status, err
	}
	opts.SessionPath = sessionPath

	var sourceChildID string
	var sourceGeneration int
	switch opts.Role {
	case RotationRoleChild:
		state, err = bindRotationChildSource(state, opts)
		if err != nil {
			return original, status, err
		}
		sourceChildID = state.ActiveChild.ID
		sourceGeneration = state.ActiveChild.Generation
	case RotationRoleManager:
		if strings.TrimSpace(state.ManagerSessionPath) == "" {
			state.ManagerSessionPath = sessionPath
		} else if !sameCleanPath(state.ManagerSessionPath, sessionPath) {
			return original, status, fmt.Errorf(
				"manager session %q does not match current manager session %q",
				sessionPath,
				state.ManagerSessionPath,
			)
		}
	}

	sample := managerUsageSample(opts.Usage, now)
	state.LastManagerUsage = sample
	percent, known := managerUsagePercent(opts.Usage)
	if !known {
		status.Reason = "unknown_usage"
		return state, status, nil
	}
	if percent < threshold {
		status.Reason = "below_threshold"
		return state, status, nil
	}

	existing := rotationForRole(state, opts.Role)
	if existing != nil {
		switch existing.Phase {
		case RotationRequested, RotationHandoffReady, RotationReplacing:
			if !rotationSourceMatches(
				*existing,
				opts.Role,
				sourceChildID,
				sourceGeneration,
				sessionPath,
			) {
				return original, status, errors.New(
					"a different source already owns the pending rotation",
				)
			}
			status.Reason = "rotation_pending"
			status.RotationID = existing.ID
			return state, status, nil
		case RotationSuccessorReady:
			if !rotationCurrentSuccessorMatches(
				state,
				*existing,
				opts.Role,
				sessionPath,
			) {
				return original, status, errors.New(
					"rotation request source is not the current persisted successor",
				)
			}
		}
	}

	rotationID := newRotationID(opts.Role, sourceChildID, sessionPath, now)
	requestedAt := now.Format(time.RFC3339Nano)
	rotation := &SessionRotation{
		ID:                rotationID,
		Role:              opts.Role,
		Phase:             RotationRequested,
		SourceNodeID:      state.Workflow.CurrentNodeID,
		SourceSessionPath: sessionPath,
		SourceChildID:     sourceChildID,
		SourceGeneration:  sourceGeneration,
		ThresholdPercent:  threshold,
		RequestedAt:       requestedAt,
		UpdatedAt:         requestedAt,
	}
	if sample != nil {
		rotation.Usage = *sample
	}
	setRotationForRole(&state, opts.Role, rotation)
	status.Requested = true
	status.Reason = "threshold_met"
	status.RotationID = rotationID
	status.Prompt = rotationPrompt(state, *rotation, opts.StateFile)
	return state, status, nil
}

func bindRotationChildSource(
	state ManagerState,
	opts RotationRequestOptions,
) (ManagerState, error) {
	if state.ActiveChild == nil {
		return state, errors.New("no active child owns the rotation request")
	}
	if state.ActiveChild.ID != strings.TrimSpace(opts.ChildID) {
		return state, fmt.Errorf(
			"active child %q does not match requested child %q",
			state.ActiveChild.ID,
			opts.ChildID,
		)
	}
	if state.ActiveChild.Stage != string(state.Workflow.CurrentNodeID) {
		return state, fmt.Errorf(
			"active child stage %q does not match current node %q",
			state.ActiveChild.Stage,
			state.Workflow.CurrentNodeID,
		)
	}
	if err := requireSessionInsideDir(
		opts.SessionPath,
		state.ActiveChild.SessionDir,
	); err != nil {
		return state, err
	}
	active := *state.ActiveChild
	if strings.TrimSpace(active.SessionPath) == "" {
		header, err := readSessionHeader(opts.SessionPath)
		if err != nil {
			return state, fmt.Errorf("read child session header: %w", err)
		}
		if header.Type != "session" || header.ID != active.SessionID {
			return state, fmt.Errorf(
				"child session header %q does not match active session %q",
				header.ID,
				active.SessionID,
			)
		}
		if strings.TrimSpace(active.Cwd) != "" && header.Cwd != active.Cwd {
			return state, fmt.Errorf(
				"child session cwd %q does not match active cwd %q",
				header.Cwd,
				active.Cwd,
			)
		}
		active.SessionPath = opts.SessionPath
		state.ActiveChild = &active
	} else if !sameCleanPath(active.SessionPath, opts.SessionPath) {
		return state, fmt.Errorf(
			"child session %q does not match active session %q",
			opts.SessionPath,
			active.SessionPath,
		)
	}
	return state, nil
}

func canonicalSessionPath(path string) (string, error) {
	path = strings.TrimSpace(path)
	absolute, err := filepath.Abs(path)
	if err != nil {
		return "", err
	}
	real, err := filepath.EvalSymlinks(absolute)
	if err != nil {
		return "", fmt.Errorf("resolve session path: %w", err)
	}
	info, err := os.Stat(real)
	if err != nil {
		return "", err
	}
	if !info.Mode().IsRegular() || filepath.Ext(real) != ".jsonl" {
		return "", fmt.Errorf("session path %q must be a regular JSONL file", real)
	}
	header, err := readSessionHeader(real)
	if err != nil {
		return "", fmt.Errorf("read session header: %w", err)
	}
	if header.Type != "session" || strings.TrimSpace(header.ID) == "" {
		return "", fmt.Errorf("session path %q has an invalid session header", real)
	}
	return filepath.Clean(real), nil
}

func requireSessionInsideDir(sessionPath, sessionDir string) error {
	if strings.TrimSpace(sessionDir) == "" {
		return errors.New("active child session directory is required")
	}
	realDir, err := filepath.EvalSymlinks(sessionDir)
	if err != nil {
		return fmt.Errorf("resolve child session directory: %w", err)
	}
	rel, err := filepath.Rel(realDir, sessionPath)
	if err != nil {
		return err
	}
	if pathEscapesRoot(rel) {
		return fmt.Errorf(
			"child session %q escapes active session directory %q",
			sessionPath,
			realDir,
		)
	}
	return nil
}

func rotationForRole(state ManagerState, role RotationRole) *SessionRotation {
	if role == RotationRoleManager {
		return state.Rotations.Manager
	}
	return state.Rotations.Child
}

func setRotationForRole(
	state *ManagerState,
	role RotationRole,
	rotation *SessionRotation,
) {
	if role == RotationRoleManager {
		state.Rotations.Manager = rotation
		return
	}
	state.Rotations.Child = rotation
}

func rotationSourceMatches(
	rotation SessionRotation,
	role RotationRole,
	childID string,
	generation int,
	sessionPath string,
) bool {
	if rotation.Role != role || !sameCleanPath(rotation.SourceSessionPath, sessionPath) {
		return false
	}
	if role == RotationRoleChild {
		return rotation.SourceChildID == childID &&
			rotation.SourceGeneration == generation
	}
	return true
}

func rotationCurrentSuccessorMatches(
	state ManagerState,
	rotation SessionRotation,
	role RotationRole,
	sessionPath string,
) bool {
	if role == RotationRoleManager {
		return strings.TrimSpace(rotation.SuccessorSessionPath) != "" &&
			sameCleanPath(rotation.SuccessorSessionPath, sessionPath) &&
			sameCleanPath(state.ManagerSessionPath, sessionPath)
	}
	return state.ActiveChild != nil &&
		rotation.SuccessorChildID == state.ActiveChild.ID &&
		sameCleanPath(state.ActiveChild.SessionPath, sessionPath)
}

func newRotationID(
	role RotationRole,
	childID, sessionPath string,
	now time.Time,
) string {
	stamp := now.UTC().Format("20060102T150405.000000000Z")
	raw := strings.Join(
		[]string{string(role), childID, filepath.Clean(sessionPath), stamp},
		"\x00",
	)
	sum := sha256.Sum256([]byte(raw))
	return fmt.Sprintf("rotation-%s-%s-%s", role, stamp, hex.EncodeToString(sum[:4]))
}

func rotationPrompt(
	state ManagerState,
	rotation SessionRotation,
	stateFile string,
) string {
	common := fmt.Sprintf(
		"Session rotation requested. Stop normal work now. Rotation ID: %s. Current node: %s. State file: %s. ",
		rotation.ID,
		rotation.SourceNodeID,
		stateFile,
	)
	if rotation.Role == RotationRoleChild {
		return common + fmt.Sprintf(
			"Read .pi/skills/q-handoff/SKILL.md and checkpoint the exact active graph node %s. Include rotation ID %s in the handoff notes. Emit a graph-valid fenced qrspi_result with stage %s, status: handoff, no outcome, and the handoff as primary artifact.",
			rotation.SourceNodeID,
			rotation.ID,
			rotation.SourceNodeID,
		)
	}
	return common + "Read .pi/skills/q-manager-handoff/SKILL.md, write the operational manager handoff for this rotation, and emit stage: q-manager with status: handoff and no outcome. Do not run /new; the validated CLI replacement owns that step."
}

func writeRotationRequestOutput(
	out io.Writer,
	mode string,
	status RotationRequestStatus,
) error {
	if strings.EqualFold(strings.TrimSpace(mode), "json") {
		encoder := json.NewEncoder(out)
		encoder.SetIndent("", "  ")
		return encoder.Encode(status)
	}
	if status.Requested {
		_, err := fmt.Fprintf(
			out,
			"rotation requested: %s\nprompt: %s\n",
			status.RotationID,
			status.Prompt,
		)
		return err
	}
	_, err := fmt.Fprintf(out, "rotation skipped: %s\n", status.Reason)
	return err
}

func completeChildRotation(
	state ManagerState,
	source ChildRunRef,
	continuation ChildRunRef,
	now time.Time,
) ManagerState {
	rotation := state.Rotations.Child
	if rotation == nil || rotation.Role != RotationRoleChild ||
		(rotation.Phase != RotationRequested && rotation.Phase != RotationHandoffReady) ||
		rotation.SourceChildID != source.ID ||
		rotation.SourceGeneration != source.Generation ||
		!sameCleanPath(rotation.SourceSessionPath, source.SessionPath) ||
		continuation.LaunchKind != ChildLaunchResumeHandoff ||
		continuation.ContinuationOf != source.ID ||
		strings.TrimSpace(continuation.ContinuationDeliveryID) == "" {
		return state
	}
	next := *rotation
	next.Phase = RotationSuccessorReady
	next.HandoffArtifact = continuation.ContinuationArtifact
	if state.Workflow.LastResult != nil && len(state.Workflow.LastResult.Raw) > 0 {
		next.HandoffResult = append(
			json.RawMessage(nil),
			state.Workflow.LastResult.Raw...)
	}
	next.SuccessorChildID = continuation.ID
	next.UpdatedAt = now.Format(time.RFC3339Nano)
	next.LastError = ""
	state.Rotations.Child = &next
	return state
}

func childRunRefForID(state ManagerState, id string) *ChildRunRef {
	for _, candidate := range []*ChildRunRef{state.ActiveChild, state.PendingCleanupChild} {
		if candidate != nil && candidate.ID == id {
			copy := *candidate
			return &copy
		}
	}
	return nil
}

func sameCleanPath(left, right string) bool {
	if strings.TrimSpace(left) == "" || strings.TrimSpace(right) == "" {
		return false
	}
	return comparablePath(left) == comparablePath(right)
}

func comparablePath(path string) string {
	path = strings.TrimSpace(path)
	if absolute, err := filepath.Abs(path); err == nil {
		path = absolute
	}
	if real, err := filepath.EvalSymlinks(path); err == nil {
		path = real
	}
	return filepath.Clean(path)
}

func clockOrNow(d deps) func() time.Time {
	if d.Clock != nil {
		return d.Clock
	}
	return time.Now
}

